using UnityEngine;

/// <summary>
/// Auras visuais pós-game (Tarefa #34) — activa/desactiva efeitos visuais no
/// player de acordo com os Emblemas globais obtidos (Gaia, Apolo, Zeus):
///
/// - <b>Aura de Gaia</b>: activa quando o Emblema de Gaia está obtido.
/// - <b>Aura de Apolo</b>: activa quando o Emblema de Apolo está obtido.
/// - <b>Aura de Zeus</b>: activa quando o Emblema de Zeus está obtido.
///
/// Cada aura é um <see cref="GameObject"/> (tipicamente um sistema de partículas
/// ou um SpriteRenderer com animação, configurado no Inspector) filho do player.
/// Este componente limita-se a activar/desactivar esses GameObjects com base no
/// estado dos emblemas.
///
/// Fluxo:
/// 1. Em <c>OnEnable</c>, subscreve <see cref="EmblemManager.EmblemGranted"/> para
///    reagir em tempo real quando um emblema é concedido durante a sessão.
/// 2. Em <c>Start</c>, lê o estado actual das variáveis de emblema (catch-up
///    para saves carregados já com emblemas obtidos).
/// 3. Cada mudança aplica <see cref="ApplyAuras"/>, que activa/desactiva os
///    GameObjects de aura correspondentes.
///
/// Montagem no Editor:
/// - Adicionar este componente ao GameObject do player (ou a um filho).
/// - "gaiaAura"/"apoloAura"/"zeusAura": filhos do player com o efeito visual.
/// - "gaiaEmblem"/"apoloEmblem"/"zeusEmblem": referências ao EmblemData com
///   <c>obtainedVariable</c> preenchido — este controller lê essa variável no
///   GameVariables para saber se o emblema foi obtido.
/// </summary>
public class PostGameAuraController : MonoBehaviour
{
    [Header("Emblemas (EmblemData com obtainedVariable preenchido)")]
    [Tooltip("EmblemData do Emblema de Gaia — contém o nome da variável global que indica se foi obtido.")]
    [SerializeField] private EmblemData gaiaEmblem;
    [Tooltip("EmblemData do Emblema de Apolo — contém o nome da variável global que indica se foi obtido.")]
    [SerializeField] private EmblemData apoloEmblem;
    [Tooltip("EmblemData do Emblema de Zeus — contém o nome da variável global que indica se foi obtido.")]
    [SerializeField] private EmblemData zeusEmblem;

    [Header("GameObjects de Aura (filhos do player)")]
    [Tooltip("Efeito visual activo quando o Emblema de Gaia está obtido (partículas, glow, SpriteRenderer animado, etc.).")]
    [SerializeField] private GameObject gaiaAura;
    [Tooltip("Efeito visual activo quando o Emblema de Apolo está obtido.")]
    [SerializeField] private GameObject apoloAura;
    [Tooltip("Efeito visual activo quando o Emblema de Zeus está obtido.")]
    [SerializeField] private GameObject zeusAura;

    private void OnEnable()
    {
        EmblemManager.EmblemGranted += OnEmblemGranted;

        if (GameSettings.Instance != null)
            GameSettings.Instance.SettingsChanged += ApplyAuras;
    }

    private void OnDisable()
    {
        EmblemManager.EmblemGranted -= OnEmblemGranted;

        if (GameSettings.Instance != null)
            GameSettings.Instance.SettingsChanged -= ApplyAuras;
    }

    private void Start()
    {
        // Catch-up: aplica o estado actual ao carregar uma cena (emblemas já obtidos antes).
        ApplyAuras();
    }

    private void OnEmblemGranted(EmblemData emblem)
    {
        // Verifica se o emblema concedido é relevante para este controller.
        if (emblem == gaiaEmblem || emblem == apoloEmblem || emblem == zeusEmblem)
            ApplyAuras();
    }

    private void ApplyAuras()
    {
        var vars = GameVariables.Instance;
        var settings = GameSettings.Instance;

        // Zeus é o troféu máximo: quando obtido, substitui Gaia e Apolo
        // (as três auras NÃO ficam activas ao mesmo tempo — GDD).
        bool zeusObtained = zeusEmblem != null
            && !string.IsNullOrEmpty(zeusEmblem.obtainedVariable)
            && (vars?.GetBool(zeusEmblem.obtainedVariable) ?? false);

        // Respeita o toggle do jogador — aura só aparece se obtida E toggle ligado.
        bool zeusEnabled = settings == null || settings.ZeusAuraEnabled;
        if (zeusAura != null) zeusAura.SetActive(zeusObtained && zeusEnabled);

        // Gaia e Apolo só ficam activas se Zeus ainda não foi obtido (ou obtido mas com toggle desligado).
        bool zeusVisible = zeusObtained && zeusEnabled;

        bool gaiaObtained = !zeusVisible && gaiaEmblem != null
            && !string.IsNullOrEmpty(gaiaEmblem.obtainedVariable)
            && (vars?.GetBool(gaiaEmblem.obtainedVariable) ?? false);

        bool apoloObtained = !zeusVisible && apoloEmblem != null
            && !string.IsNullOrEmpty(apoloEmblem.obtainedVariable)
            && (vars?.GetBool(apoloEmblem.obtainedVariable) ?? false);

        bool gaiaEnabled = settings == null || settings.GaiaAuraEnabled;
        bool apoloEnabled = settings == null || settings.ApoloAuraEnabled;

        if (gaiaAura != null)  gaiaAura.SetActive(gaiaObtained && gaiaEnabled);
        if (apoloAura != null) apoloAura.SetActive(apoloObtained && apoloEnabled);
    }
}
